VALUES
  ('elementary-0489de64-moex-00181', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '都市綜合運輸規劃（ComprehensiveTransportationPlanning），展望未來之規畫期間，通常時間跨度 應為下列何者？', '["1至2年時間", "3至5年時間", "10年左右時間", "20至30年或更長的時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00182', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '對於公共運輸導向發展（TransitOrientedDevelopment,TOD）之都市政策，下列那一項陳述錯誤？', '["TOD的重點是每一個捷運車站之建築與景觀設計，車站內之通道設計與公共藝術展示，以及捷運 車站與周邊建築之連接", "TOD之城市層面：協調與確定城市結構、軌道交通廊道、道路結構與主要樞紐的關係，強化公共 交通支撐和引導城市土地使用的開發", "TOD之線路層面：協調與確定軌道沿線影響區與網站周邊地區的功能定位、建設規模、交通設施 等的設置要求以及公共空間系統的引導要求", "TOD之網站層面：協調與確定軌道網站與周邊物業發展、交通換乘空間及城市空間的立體對接關 係，對網站出入口、步行系統的設置提出詳細引導要求，相關引導要求納入控制性詳細規劃"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00183', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '一條公共汽車路線全長10公里，共6車站：A→B2公里，B→C1公里，C→D1.5公里，D→E 3公里，E→F2.5公里。尖峰小時下行方向旅客需求（區段客流人數）：A→B245人，B→C310人， C→D400人，D→E350人，E→F300人，如下圖所示。若政策性每一車輛最大承載人數（座位與站 位）50人，決定路線尖峰小時服務所需的班次數（班車/小時）為：', '["4（班車/小時），15分鐘一班車", "6（班車/小時），10分鐘一班車", "8（班車/小時），7.5分鐘一班車", "10（班車/小時），6分鐘一班車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00184', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '一條公共汽車路線，11個車站，尖峰小時下行方向，各車站上下人數如下表所示。客流最大承載區 段為：', '["4→5", "5→6", "6→7", "7→8"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00185', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '大眾捷運系統（MRT）路線於A與B兩終點站間往返行駛，運營每站皆停之列車。一部列車之營運 週期：自起站A出發，各站皆停，到終站B後，列車折返；接著，由終站B出發，各站皆停，至起 站A，再列車折返。列車運營：去程24分鐘，回程相同為24分鐘，一次端點站內折返3分鐘。尖峰 期間每6分鐘開一列車，亦即列車間班距（headway）為6分鐘。尖峰期間所需之列車數量（列）為：', '["6", "7", "8", "9"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00186', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '日本湘南懸掛式單軌鐵路，是神奈川城市的生活與觀光線路，7公里，單線運轉，運營速度 28 公里/小時。時刻表顯示：對稱發車，單一方向，尖峰時段8列車/小時。運行EMU500列車，3節1組， 座位與站位滿載時496人位/列車；最高速度75公里/小時，最大加速度4.0 km/h/s，最大減速度', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00187', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '0km/h/s（4.5km/h/s）。時刻表反映之實際運能（人/小時-單一方向）為：', '["224", "2100", "3968", "13888"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
